#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void swap(int& a, int& b) {
        a = a ^ b;
        b = a ^ b;
        a = a ^ b;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int a, b, n;
    if (!(cin >> a >> b >> n)) return 0;
    Solution sol;
    sol.swap(a, b);
    cout << a << endl;
    cout << b << endl;
    return 0;
}
